select
    t.task_id, t.out_put_poll_id, t.task_date, t.check_frequency, p.execution_standard, t.monitor_unit, ext.unit_name as monitorUnitName, t.task_desc, t.report_name,
    t.report_code, t.monitor_category, t.sample_date, t.report_date, t.analysis_person, t.contact_person, t.contact_phone,
    t.status, t.update_time, o.out_put_id, o.out_put_name, o.out_put_type, op.pollutant_code, pc.pollutant_name_cn, pc.pollutant_name_en, op.over_maxValue, op.over_minValue,
    t.analysis_start_date, t.analysis_end_date, t.sampling_person, t.operation_hour
from t_env_manual_check_task t
left join t_env_manual_check_plan p on p.out_put_poll_id = t.out_put_poll_id
left join t_ent_output_pollutant op on op.out_put_poll_id = t.out_put_poll_id
left join t_bas_pollutant_code pc on pc.pollutant_code = op.pollutant_code
left join t_ent_out_put_info o on o.out_put_id = op.out_put_id
left join t_ext_unit_lib ext on ext.unit_code = t.monitor_unit



            and o.ent_code = #{entCode}



                and o.ent_code in

                    #{entCode}





        and o.out_put_id = #{outPutId}


        and t.out_put_poll_id = #{outPutPollId}


        and t.status = #{status}


        and t.task_date between #{taskDateStart} and #{taskDateEnd}


        and t.monitor_unit = #{monitorUnit}


        and t.report_code like concat('%', #{reportCode}, '%')


        and t.status in

            #{status}



        and t.task_id in

            #{taskId}



order by o.out_put_id desc, t.out_put_poll_id desc, t.task_date desc, t.task_id desc

