update t_env_manual_check_task

    status = #{status}

        , monitor_unit = #{monitorUnit}, task_desc = #{taskDesc}


        , report_name = #{reportName}, report_code = #{reportCode}, monitor_category = #{monitorCategory},
        sample_date = #{sampleDate}, report_date = #{reportDate}, analysis_start_date = #{analysisStartDate},
        analysis_end_date = #{analysisEndDate}, analysis_person = #{analysisPerson}, sampling_person = #{samplingPerson},
        operation_hour = #{operationHour}, contact_person = #{contactPerson}, contact_phone = #{contactPhone}


where task_id = #{taskId}
